// T113 FraudDetectorHandler — CORRECT fail-open pattern
@Injectable()
export class FraudDetectorHandler {
  async check(purchase: Record<string, unknown>): Promise<{ passed: boolean }> {
    try {
      const result = await this.fraudService.analyze(purchase);
      return { passed: !result.data?.isFraudulent };
    } catch (e) {
      // FAIL OPEN: service unavailable — allow purchase + emit audit event
      await this.queue.enqueue('fraud.check.failed', {
        reason: 'service_unavailable',
        purchaseId: purchase['purchaseId'],
        occurredAt: new Date().toISOString(),
      });
      return { passed: true }; // Allow purchase to proceed
    }
  }
}
// WRONG: catch (e) { return { passed: false } } — blocks all purchases during outage
